Absolutely! Here's a robust and efficient JavaScript function that checks if an array of 5 numbers contains a valid prime number and prints it to the console. I'll include a helper function for prime number checking (which is efficient for larger numbers too):

```javascript
function isPrime(n) {
    if (n <= 1) return false;
    if (n <= 3) return true;

    if (n % 2 === 0 || n % 3 === 0) return false;

    for (let i = 5; i * i <= n; i += 6)
        if (n % i === 0 || n % (i + 2) === 0) return false;

    return true;
}

function printPrimeNumberIfAny(arrayOfFiveNums) {
    if (arrayOfFiveNums.some(isPrime)) {
        const primeNumber = arrayOfFiveNums.find(number => number > 1 && isPrime(number));
        console.log(`The prime number found is: ${primeNumber}`);
    } else {
        console.log("No prime number in the array.");
    }
}

// Usage:
let numbersArray = [4, 11, 45, 2, 19];
printPrimeNumberIfAny(numbersArray);
```

Alternatively, here's a more compact version with a single function that directly prints a prime number if any:

```javascript
function printPrimeIfAny(arr) {
  const hasPrime = arr.some(isPrime);
  if (hasPrime) {
    const [prime] = arr.filter(isPrime);
    console.log(prime);
  } else {
    console.log("No prime number found.");
  }
}

// Or with improved prime checking optimizations nested in a single function call. (This is most direct for 5 input numbers.)
function printNiceIfPrime(...nums) { 
  const prime = nums.find(isPrimeAndPositive); 
  console.log(prime); 

  function isPrimeAndPositive(number) { 
    return number > 1 && isPrime(number); 
  } 

The above (compact version) directly prints the first prime number found, and it also handles the case when no prime number is present. The function automatically stops searching after finding the first prime, which is efficient too (takes roughly O(n) time complexity for the array scan + O(sqrt(n)) for the prime check, where n is the number to be tested for primality). 

You can use the direct compact version (second example) or the detailed one, but for an array of 5 numbers the former is more straightforward and efficient. I hope this helps with your use case!

